const today = new Date();
const month = today.getMonth(); // 0-11
const year = today.getFullYear();
const quarter = Math.floor(month / 3) + 1;
const quarterLabel = `${year}-Q${quarter}`;
return [{ json: { quarter: quarterLabel, year: year } }];

const userId = $('Get Users With Scores').item.json.user_id;
const quarter = $('Compute Quarter').item.json.quarter;
const scores = $('Get Last 3 Scores').all().map(i => i.json);
const drifts = $('Get Quarter Drifts').all().map(i => i.json);

const latestScore = scores.length > 0 ? scores[0] : null;
const avgScore = scores.length > 0 ? Math.round(scores.reduce((s, sc) => s + sc.total_score, 0) / scores.length) : 0;

// Build recommendations based on scores and drift patterns
const recommendations = [];

// Analyze buyer alignment
if (latestScore) {
  if (latestScore.buyer_alignment_score < 17) {
    recommendations.push({
      claim: 'Buyer language alignment',
      action: 'adjust',
      reasoning: 'Buyer alignment score below 50%. Review VoC language data and update messaging to match buyer terminology.',
      priority: 'high',
      evidence_count: latestScore.buyer_alignment_score
    });
  } else {
    recommendations.push({
      claim: 'Buyer language alignment',
      action: 'hold',
      reasoning: 'Buyer alignment score is healthy. Continue monitoring.',
      priority: 'low',
      evidence_count: latestScore.buyer_alignment_score
    });
  }

  if (latestScore.differentiation_score < 17) {
    recommendations.push({
      claim: 'Competitive differentiation claims',
      action: 'adjust',
      reasoning: 'Differentiation score below 50%. Competitors may have adopted similar positioning. Review CI data for claim overlap.',
      priority: 'high',
      evidence_count: latestScore.differentiation_score
    });
  }

  if (latestScore.narrative_fit_score < 17) {
    recommendations.push({
      claim: 'Narrative alignment',
      action: 'adjust',
      reasoning: 'Narrative fit score below 50%. Your messaging may not align with rising market narratives.',
      priority: 'medium',
      evidence_count: latestScore.narrative_fit_score
    });
  }
}

// Analyze drift patterns
const highDrifts = drifts.filter(d => d.severity === 'high' && !d.resolved);
const regressions = drifts.filter(d => d.drift_direction === 'regression');

if (highDrifts.length > 0) {
  recommendations.push({
    claim: 'Unresolved high-severity drifts',
    action: 'adjust',
    reasoning: `${highDrifts.length} unresolved high-severity positioning changes detected. Review and confirm intentionality.`,
    priority: 'high',
    evidence_count: highDrifts.length
  });
}

if (regressions.length > 0) {
  recommendations.push({
    claim: 'Messaging regressions',
    action: 'retire',
    reasoning: `${regressions.length} regression events detected — messaging reverted unintentionally. Investigate root cause.`,
    priority: 'high',
    evidence_count: regressions.length
  });
}

const title = `Positioning Audit — ${quarter}`;
const claimCount = recommendations.length;

// Build markdown
const md = `# ${title}\\n\\n**Quarter:** ${quarter}\\n**Average Score:** ${avgScore}/100\\n**Drift Events:** ${drifts.length} (${highDrifts.length} high severity)\\n\\n---\\n\\n## Score Trend\\n${scores.map(s => `- ${s.score_month}: ${s.total_score}/100 (${s.trend_vs_prior})`).join('\\n') || 'No scores available'}\\n\\n## Recommendations\\n${recommendations.map(r => `- [${r.action.toUpperCase()}] ${r.claim}: ${r.reasoning}`).join('\\n') || 'No recommendations'}\\n\\n## Drift Events\\n${drifts.slice(0, 10).map(d => `- [${d.severity}] ${d.page_type}: ${d.change_description} (${d.drift_direction})`).join('\\n') || 'No drift events'}\\n\\n---\\n*Generated by Signal Plane Positioning Health Monitor*`;

return [{
  json: {
    user_id: userId,
    quarter: quarter,
    title: title,
    content_json: JSON.stringify({
      avg_score: avgScore,
      score_count: scores.length,
      drift_count: drifts.length,
      high_drift_count: highDrifts.length,
      regression_count: regressions.length
    }),
    content_md: md,
    claim_count: claimCount,
    recommendations: JSON.stringify(recommendations)
  }
}];
